function initiateModifyTimelockExpiration(
  bytes4 functionSelector, uint256 newTimelockExpiration, uint256 extraTime
) external onlyOwner {
  // Ensure that a function selector is specified (no 0x00000000 selector).
  require(
    functionSelector != bytes4(0),
    "Function selector cannot be empty."
  );

  // Ensure that the supplied default expiration does not exceed 1 month.
  require(
    newTimelockExpiration <= 30 days,
    "New timelock expiration cannot exceed one month."
  );

  // Ensure a timelock expiration under one hour is not set on this function.
  if (functionSelector == this.modifyTimelockExpiration.selector) {
    require(
      newTimelockExpiration >= 60 minutes,
      "Expiration of modifyTimelockExpiration must be at least an hour long."
    );
  }

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.modifyTimelockExpiration.selector,
    abi.encode(functionSelector, newTimelockExpiration),
    extraTime
  );
}

function newKeyRingAndDaiWithdrawal(
  address userSigningKey,
  address targetKeyRing,
  address smartWallet,
  uint256 amount,
  address recipient,
  uint256 minimumActionGas,
  bytes calldata userSignature,
  bytes calldata dharmaSignature
) external returns (address keyRing, bool withdrawalSuccess) {
  // Declare the interface for the supplied smart wallet.
  DharmaSmartWalletImplementationV0Interface wallet = (
    DharmaSmartWalletImplementationV0Interface(smartWallet)
  );

  // Ensure target key ring is set as user signing key on the smart wallet.
  require(
    wallet.getUserSigningKey() == targetKeyRing,
    "Target key ring is not set as user signing key on supplied smart wallet."
  );

  // Deploy and initialize a keyring if needed and emit a corresponding event.
  keyRing = _deployNewKeyRingIfNeeded(userSigningKey, targetKeyRing);

  // Attempt to withdraw Dai from the provided smart wallet.
  withdrawalSuccess = wallet.withdrawDai(
    amount, recipient, minimumActionGas, userSignature, dharmaSignature
  );
}

