function getFirstSmartWalletCustomActionID(
  address userSigningKey,
  address smartWallet,
  DharmaSmartWalletImplementationV0Interface.ActionType action,
  uint256 amount,
  address recipient,
  uint256 minimumActionGas
) external view returns (bytes32 actionID) {
  // Determine the actionID - this serves as a signature hash for an action.
  if (
    action == DharmaSmartWalletImplementationV0Interface.ActionType.Cancel
  ) {
    // actionID is constructed according to EIP-191-0x45 to prevent replays.
    actionID = keccak256(
      abi.encodePacked(
        smartWallet,
        _getSmartWalletVersion(),
        userSigningKey,
        _getDharmaSigningKey(smartWallet),
        uint256(0),
        minimumActionGas,
        action
      )
    );
  } else {
    // actionID is constructed according to EIP-191-0x45 to prevent replays.
    actionID = keccak256(
      abi.encodePacked(
        smartWallet,
        _getSmartWalletVersion(),
        userSigningKey,
        _getDharmaSigningKey(smartWallet),
        uint256(0),
        minimumActionGas,
        action,
        abi.encode(amount, recipient)
      )
    );
  }
}

function recoverGroup(
  bytes32 hash,
  bytes memory signatures
) internal pure returns (uint160[] memory signers) {
  // Ensure that the signatures length is a multiple of 65.
  if (signatures.length % 65 != 0) {
    return new uint160[](0);
  }

  // Create an appropriately-sized array of addresses for each signer.
  signers = new uint160[](signatures.length / 65);

  // Get each signature location and divide into r, s and v variables.
  bytes32 signatureLocation;
  bytes32 r;
  bytes32 s;
  uint8 v;

  for (uint256 i = 0; i < signers.length; i++) {
    assembly {
      signatureLocation := add(signatures, mul(i, 65))
      r := mload(add(signatureLocation, 0x20))
      s := mload(add(signatureLocation, 0x40))
      v := byte(0, mload(add(signatureLocation, 0x60)))
    }

    // EIP-2 still allows signature malleability for ecrecover(). Remove
    // this possibility and make the signature unique.
    if (uint256(s) > 0x7FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF5D576E7357A4501DDFE92F46681B20A0) {
      continue;
    }

    if (v != 27 && v != 28) {
      continue;
    }

    // If signature is valid & not malleable, add signer address as uint160.
    signers[i] = uint160(ecrecover(hash, v, r, s));
  }
}

function _setTimelockExpirationPrivate(
  bytes4 functionSelector, uint256 newTimelockExpiration
) private {
  // Ensure that the new timelock expiration will not cause an overflow error.
  require(
    newTimelockExpiration < _A_TRILLION_YEARS,
    "Supplied default timelock expiration is too large."
  );

  // Ensure that the new timelock expiration is not too short.
  require(
    newTimelockExpiration > 1 minutes,
    "New timelock expiration is too short."
  );

  // Get the existing timelock expiration, if any.
  uint256 oldTimelockExpiration = uint256(
    _timelockDefaults[functionSelector].expiration
  );

  // Update the timelock expiration on the provided function.
  _timelockDefaults[functionSelector].expiration = uint128(
    newTimelockExpiration
  );

  // Emit a `TimelockExpirationModified` event with the appropriate arguments.
  emit TimelockExpirationModified(
    functionSelector, oldTimelockExpiration, newTimelockExpiration
  );
}

function initialize(
  uint128 adminThreshold,
  uint128 executorThreshold,
  address[] calldata keys,
  uint8[] calldata keyTypes // must all be 3 (Dual) for V1
) external {
  // Ensure that this function is only callable during contract construction.
  assembly { if extcodesize(address) { revert(0, 0) } }

  // V1 only allows setting a singly Dual key with thresholds both set to 1.
  require(keys.length == 1, "Must supply exactly one key in V1.");

  require(keys[0] != address(0), "Cannot supply the null address as a key.");

  require(
    keyTypes.length == 1 && keyTypes[0] == uint8(3),
    "Must supply exactly one Dual keyType (3) in V1."
  );

  require(adminThreshold == 1, "Admin threshold must be exactly one in V1.");

  require(
    executorThreshold == 1, "Executor threshold must be exactly one in V1."
  );

  // Set the key and emit a corresponding event.
  _keys[uint160(keys[0])] = KeyType.Dual;
  emit KeyModified(keys[0], true, true);

  // Note: skip additional key counts + thresholds setup in V1 (only one key).
}

function takeAdminAction(
  AdminActionType adminActionType, uint160 argument, bytes calldata signatures
) external {
  // Only Admin Action Type 6 (AddDualKey) is supported in V1.
  require(
    adminActionType == AdminActionType.AddDualKey,
    "Only adding new Dual key types (admin action type 6) is supported in V1."
  );

  require(argument != uint160(0), "Cannot supply the null address as a key.");

  require(_keys[argument] == KeyType.None, "Key already exists.");

  // Verify signature against a hash of the prefixed admin admin actionID.
  _verifySignature(
    _getAdminActionID(argument, _nonce).toEthSignedMessageHash(), signatures
  );

  // Increment the key count for both standard and admin keys.
  _additionalKeyCounts.standard++;
  _additionalKeyCounts.admin++;

  // Set the key and emit a corresponding event.
  _keys[argument] = KeyType.Dual;
  emit KeyModified(address(argument), true, true);

  // Increment the nonce.
  _nonce++;
}

function migrateCSaiToCDai() external {
  // Get the current cSai balance for this account.
  uint256 redeemAmount = _CSAI.balanceOf(address(this));

  // Only perform the call to redeem if there is a non-zero balance.
  if (redeemAmount > 0) {
    // Get the current Sai balance on this contract.
    uint256 currentSaiBalance = _SAI.balanceOf(address(this));

    // Redeem underlying balance from cSai and revert if unsuccessful.
    require(
      _CSAI.redeem(redeemAmount) == _COMPOUND_SUCCESS, "cSai redeem failed."
    );

    // Calculate difference between pre-redeem and post-redeem Sai balances.
    uint256 saiBalance = _SAI.balanceOf(address(this)) - currentSaiBalance;

    // Swap any Sai for Dai and get the newly-swapped Dai balance.
    uint256 daiBalance = _swapSaiForDai(saiBalance);

    // If the cDai allowance is insufficient, set it before depositing.
    if (_DAI.allowance(address(this), address(_CDAI)) < daiBalance) {
      require(
        _DAI.approve(address(_CDAI), uint256(-1)), "Dai approval failed."
      );
    }

    // Deposit the new Dai balance on Compound.
    require(_CDAI.mint(daiBalance) == _COMPOUND_SUCCESS, "cDai mint failed.");
  }
}

function _swapSaiForDai(uint256 saiToSwap) internal returns (uint256 dai) {
  // If the balance is non-zero, check if migrator has adequate approval.
  if (saiToSwap > 0) {
    uint256 allowance = _SAI.allowance(address(this), address(_MIGRATOR));

    // Ensure that allowance is sufficient before calling the migrator.
    if (saiToSwap > allowance) {
      // Approve migrator contract to transfer Sai on behalf of this wallet.
      require(
        _SAI.approve(address(_MIGRATOR), uint256(-1)), "Sai approval failed."
      );
    }

    // Get the current Dai balance on this contract.
    uint256 currentDaiBalance = _DAI.balanceOf(address(this));

    // Call migrator contract to swap the supplied Sai balance for Dai.
    _MIGRATOR.swapSaiToDai(saiToSwap);

    // Return the difference between the pre-swap and post-swap Dai balances.
    dai = _DAI.balanceOf(address(this)) - currentDaiBalance;

    // Ensure that the Sai-to-Dai exchange rate was at least 1-to-1.
    require(dai >= saiToSwap, "Exchange rate cannot be below 1:1.");
  } else {
    // Explicitly specify a change in balance of zero if no swap occurred.
    dai = 0;
  }
}

function _swapSaiForDai(uint256 saiToSwap) internal returns (uint256 dai) {
  // If the balance is non-zero, check if migrator has adequate approval.
  if (saiToSwap > 0) {
    uint256 allowance = _SAI.allowance(address(this), address(_MIGRATOR));

    // Ensure that allowance is sufficient before calling the migrator.
    if (saiToSwap > allowance) {
      // Approve migrator contract to transfer Sai on behalf of this wallet.
      require(
        _SAI.approve(address(_MIGRATOR), uint256(-1)), _revertReason(15)
      );
    }

    // Get the current Dai balance on this contract.
    uint256 currentDaiBalance = _DAI.balanceOf(address(this));

    // Call migrator contract to swap the supplied Sai balance for Dai.
    _MIGRATOR.swapSaiToDai(saiToSwap);

    // Return the difference between the pre-swap and post-swap Dai balances.
    dai = _DAI.balanceOf(address(this)) - currentDaiBalance;

    // Ensure that the Sai-to-Dai exchange rate was at least 1-to-1.
    require(dai >= saiToSwap, _revertReason(16));
  } else {
    // Explicitly specify a change in balance of zero if no swap occurred.
    dai = 0;
  }
}

function mintViaCToken(
  uint256 cTokensToSupply
) external returns (uint256 dTokensMinted) {
  // Instantiate the interface for the backing cToken.
  CTokenInterface cToken = CTokenInterface(_getCToken());

  // Pull in cTokens - ensure that this contract has sufficient allowance.
  (bool ok, bytes memory data) = address(cToken).call(abi.encodeWithSelector(
    cToken.transferFrom.selector, msg.sender, address(this), cTokensToSupply
  ));
  _checkCompoundInteraction(cToken.transferFrom.selector, ok, data);

  // Accrue interest and retrieve current cToken and dToken exchange rates.
  (uint256 dTokenExchangeRate, uint256 cTokenExchangeRate) = _accrue(true);

  // Determine the underlying equivalent of the supplied cToken amount.
  uint256 underlyingEquivalent = _toUnderlying(
    cTokensToSupply, cTokenExchangeRate, false
  );

  // Determine dTokens to mint using underlying equivalent and exchange rate.
  dTokensMinted = _fromUnderlying(
    underlyingEquivalent, dTokenExchangeRate, false
  );

  // Mint dTokens to the caller.
  _mint(msg.sender, underlyingEquivalent, dTokensMinted);
}

function redeemToCToken(
  uint256 dTokensToBurn
) external returns (uint256 cTokensReceived) {
  // Instantiate the interface for the backing cToken.
  CTokenInterface cToken = CTokenInterface(_getCToken());

  // Accrue interest and retrieve current cToken and dToken exchange rates.
  (uint256 dTokenExchangeRate, uint256 cTokenExchangeRate) = _accrue(true);

  // Determine the underlying token value of the dTokens to be burned.
  uint256 underlyingEquivalent = _toUnderlying(
    dTokensToBurn, dTokenExchangeRate, false
  );

  // Determine amount of cTokens corresponding to underlying equivalent value.
  cTokensReceived = _fromUnderlying(
    underlyingEquivalent, cTokenExchangeRate, false
  );

  // Burn the dTokens.
  _burn(msg.sender, underlyingEquivalent, dTokensToBurn);

  // Transfer cTokens to the caller and ensure that the operation succeeds.
  (bool ok, bytes memory data) = address(cToken).call(abi.encodeWithSelector(
    cToken.transfer.selector, msg.sender, cTokensReceived
  ));
  _checkCompoundInteraction(cToken.transfer.selector, ok, data);
}

function redeemUnderlyingToCToken(
  uint256 underlyingToReceive
) external returns (uint256 dTokensBurned) {
  // Instantiate the interface for the backing cToken.
  CTokenInterface cToken = CTokenInterface(_getCToken());

  // Accrue interest and retrieve current cToken and dToken exchange rates.
  (uint256 dTokenExchangeRate, uint256 cTokenExchangeRate) = _accrue(true);

  // Get received cTokens and underlying equivalent (prevent "dust" griefing).
  (
    uint256 cTokensToReceive, uint256 underlyingEquivalent
  ) = _fromUnderlyingAndBack(
    underlyingToReceive, cTokenExchangeRate, false, true // round down cTokens
  );

  // Determine redeemed dTokens using equivalent underlying value, rounded up.
  dTokensBurned = _fromUnderlying(
    underlyingEquivalent, dTokenExchangeRate, true
  );

  // Burn the dTokens.
  _burn(msg.sender, underlyingToReceive, dTokensBurned);

  // Transfer cTokens to the caller and ensure that the operation succeeds.
  (bool ok, bytes memory data) = address(cToken).call(abi.encodeWithSelector(
    cToken.transfer.selector, msg.sender, cTokensToReceive
  ));
  _checkCompoundInteraction(cToken.transfer.selector, ok, data);
}

function _getSurplus() private view returns (
  uint256 underlyingSurplus, uint256 cTokenSurplus
) {
  // Instantiate the interface for the backing cToken.
  CTokenInterface cToken = CTokenInterface(_getCToken());

  (
    uint256 dTokenExchangeRate, uint256 cTokenExchangeRate,
  ) = _getExchangeRates(true);

  // Determine value of all issued dTokens in the underlying, rounded up.
  uint256 dTokenUnderlying = _toUnderlying(
    _totalSupply, dTokenExchangeRate, true
  );

  // Determine value of all retained cTokens in the underlying, rounded down.
  uint256 cTokenUnderlying = _toUnderlying(
    cToken.balanceOf(address(this)), cTokenExchangeRate, false
  );

  // Determine the size of the surplus in terms of underlying amount.
  underlyingSurplus = cTokenUnderlying > dTokenUnderlying
    ? cTokenUnderlying - dTokenUnderlying // overflow checked above
    : 0;

  // Determine the cToken equivalent of this surplus amount.
  cTokenSurplus = underlyingSurplus == 0
    ? 0
    : _fromUnderlying(underlyingSurplus, cTokenExchangeRate, false);
}

function execute(
  bytes calldata data,
  address executor,
  uint256 gasLimit,
  bytes calldata signatures
) external returns (bool success, bytes memory returnData) {
  require(
    executor == msg.sender || executor == address(0),
    "Must call from the executor account if one is specified."
  );

  // Derive the message hash and wrap in the eth signed messsage hash.
  bytes32 hash = _toEthSignedMessageHash(
    _getHash(data, executor, gasLimit, _nonce)
  );

  // Recover each signer from the provided signatures.
  address[] memory signers = _recoverGroup(hash, signatures);

  require(signers.length == _THRESHOLD, "Total signers must equal threshold.");

  // Verify that each signatory is an owner and is strictly increasing.
  address lastAddress = address(0); // cannot have address(0) as an owner
  for (uint256 i = 0; i < signers.length; i++) {
    require(
      _isOwner[signers[i]], "Signature does not correspond to an owner."
    );
    require(
      signers[i] > lastAddress, "Signer addresses must be strictly increasing."
    );
    lastAddress = signers[i];
  }

  // Increment the nonce and execute the transaction.
  _nonce++;
  (success, returnData) = _DESTINATION.call.gas(gasLimit)(data);
}

function _recoverGroup(
  bytes32 hash,
  bytes memory signatures
) internal pure returns (address[] memory signers) {
  // Ensure that the signatures length is a multiple of 65.
  if (signatures.length % 65 != 0) {
    return new address[](0);
  }

  // Create an appropriately-sized array of addresses for each signer.
  signers = new address[](signatures.length / 65);

  // Get each signature location and divide into r, s and v variables.
  bytes32 signatureLocation;
  bytes32 r;
  bytes32 s;
  uint8 v;

  for (uint256 i = 0; i < signers.length; i++) {
    assembly {
      signatureLocation := add(signatures, mul(i, 65))
      r := mload(add(signatureLocation, 32))
      s := mload(add(signatureLocation, 64))
      v := byte(0, mload(add(signatureLocation, 96)))
    }

    // EIP-2 still allows signature malleability for ecrecover(). Remove
    // this possibility and make the signature unique.
    if (uint256(s) > 0x7FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF5D576E7357A4501DDFE92F46681B20A0) {
      continue;
    }

    if (v != 27 && v != 28) {
      continue;
    }

    // If signature is valid & not malleable, add signer address.
    signers[i] = ecrecover(hash, v, r, s);
  }
}

function exitAdharmaContingency(
  address smartWalletImplementation, address keyRingImplementation
) external onlyOwner {
  // Ensure that the Adharma Contingency is currently active.
  require(
    _adharma.activated, "Adharma Contingency is not currently activated."
  );

  // Ensure that at least 48 hours has elapsed since the contingency commenced.
  require(
    now > _adharma.activationTime + 48 hours,
    "Cannot exit contingency with a new upgrade until 48 hours have elapsed."
  );

  // Ensure this contract still owns the required upgrade beacon controllers.
  _ensureOwnershipOfSmartWalletAndKeyRingControllers();

  // Exit the contingency state and trigger a heartbeat.
  _exitAdharmaContingencyIfActiveAndTriggerHeartbeat();

  // Trigger upgrades on both beacons to the Adharma implementation contracts.
  _upgrade(
    _SMART_WALLET_UPGRADE_BEACON_CONTROLLER,
    _DHARMA_SMART_WALLET_UPGRADE_BEACON,
    smartWalletImplementation
  );
  _upgrade(
    _KEY_RING_UPGRADE_BEACON_CONTROLLER,
    _DHARMA_KEY_RING_UPGRADE_BEACON,
    keyRingImplementation
  );
}

function backAndForthTraverseUint()
        external
        view
        returns (uint256[] memory, uint256[] memory)
    {
        Traversal.Iterator memory iterator_ = _uintTree.first();

        uint256[] memory keys_ = new uint256[](12);
        uint256[] memory values_ = new uint256[](12);

        bool[12] memory directions_ = [
            true,
            true,
            false,
            true,
            false,
            false,
            true,
            true,
            true,
            true,
            true,
            true
        ];

        bytes32 bytesKey_;
        bytes32 bytesValue_;

        for (uint256 i = 0; i < 12; ++i) {
            (bytesKey_, bytesValue_) = iterator_.value();

            keys_[i] = uint256(bytesKey_);
            values_[i] = uint256(bytesValue_);

            directions_[i] ? iterator_.next() : iterator_.prev();
        }

        return (keys_, values_);
    }

function testNew() external pure {
    assembly {
        mstore(
            add(mload(0x40), 0x40),
            0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff
        )
    }

    Vector.UintVector memory vector1_ = Vector.newUint();

    if (vector1_.length() != 0) revert();

    assembly {
        mstore(
            add(mload(0x40), 0x60),
            0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff
        )
        mstore(
            add(mload(0x40), 0x80),
            0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff
        )
        mstore(
            add(mload(0x40), 0x100),
            0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff
        )
    }

    Vector.UintVector memory vector2_ = Vector.newUint(3);

    if (vector2_.length() != 3) revert();

    for (uint256 i = 0; i < vector2_.length(); ++i) {
        if (vector2_.at(i) != 0) revert();
    }
}

function _permitTransferFrom(
    PermitBatchTransferFrom memory permit,
    SignatureTransferDetails[] calldata transferDetails,
    address owner,
    bytes32 dataHash,
    bytes calldata signature
) private {
    uint256 numPermitted = permit.permitted.length;

    if (block.timestamp > permit.deadline) revert SignatureExpired(permit.deadline);
    if (numPermitted != transferDetails.length) revert LengthMismatch();

    _useUnorderedNonce(owner, permit.nonce);
    signature.verify(_hashTypedData(dataHash), owner);

    unchecked {
        for (uint256 i = 0; i < numPermitted; ++i) {
            TokenPermissions memory permitted = permit.permitted[i];
            uint256 requestedAmount = transferDetails[i].requestedAmount;

            if (requestedAmount > permitted.amount) revert InvalidAmount(permitted.amount);

            if (requestedAmount != 0) {
                // allow spender to specify which of the permitted tokens should be transferred
                ERC20(permitted.token).safeTransferFrom(owner, transferDetails[i].to, requestedAmount);
            }
        }
    }
}
